regime_summary &lt;- adm2_risk |&gt;
  st_drop_geometry() |&gt;
  group_by(regime_4) |&gt;
  summarise(
    adm2_areas = n(),
    departments = n_distinct(ADM1_ES),
    mean_access_share = round(mean(hospital_access_30min_share), 3),
    .groups = "drop"
  )

